import React from "react";
import { Button, Col, Row } from "react-bootstrap";
import firebase from "../controller/firebase";

export const NameInput = ({ character, docId }) => {
  console.log(character);

  const [name, setName] = React.useState(character.name);
  const [charClass, setcharClass] = React.useState("");
  const [race, setRace] = React.useState("");

  const onUpdate = async () => {
    if (name !== "" && name != null) {
      character.name = name;
    }

    if (charClass !== "" && charClass != null) {
      character.class = charClass;
    }
    if (race !== "" && race != null) {
      character.race = race;
    }
    const db = firebase.firestore();
    await db
      .collection("characters")
      .doc(docId)
      .set({ ...character });

    refreshPage();
  };

  function refreshPage() {
    window.location.reload(false);
  }

  return (
    <div className="update-card-border">
      <div className="update-card">
        <Row className="underline">
          <Col>
            <h1>Name</h1>
          </Col>
          <Col>
            <h3>{character.name}</h3>
          </Col>
          <Col>
            <input
              className="update-card-input"
              value={name}
              onChange={(e) => {
                setName(e.target.value);
              }}
            />
          </Col>
        </Row>
        <Row className="underline">
          <Col>
            <h1>Class</h1>
          </Col>
          <Col>
            <h3>{character.class}</h3>
          </Col>
          <Col>
            <input
              className="update-card-input"
              value={charClass}
              onChange={(e) => {
                setcharClass(e.target.value);
              }}
            />
          </Col>
        </Row>
        <Row className="underline">
          <Col>
            <h1>Race</h1>
          </Col>
          <Col>
            <h3>{character.race}</h3>
          </Col>
          <Col>
            <input
              className="update-card-input"
              value={race}
              onChange={(e) => {
                setRace(e.target.value);
              }}
            />
          </Col>
        </Row>
        <Button
          className="update-card-button"
          variant="dark"
          size="lg"
          block
          onClick={onUpdate}
        >
          Update
        </Button>
      </div>
    </div>
  );
};
